self.addEventListener("push",i=>{if(!i.data)return;let t=i.data.json();i.waitUntil(self.registration.showNotification(t.title,{body:t.body||"",icon:"/icons/icon-192.png",badge:"/icons/icon-192.png",dir:"rtl",lang:"he",tag:t.url||"default",data:{url:t.url||"/"}}))}),self.addEventListener("notificationclick",i=>{i.notification.close();let t=i.notification.data?.url||"/";i.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>{for(let n of i)if(n.url.includes(self.location.origin)&&"focus"in n)return n.navigate(t),n.focus();return self.clients.openWindow(t)}))});